//data
var albumList = getColumn("RollingStone: 500 Albums", "Album");
var artistList = getColumn("RollingStone: 500 Albums", "Artist");
var genreList = getColumn("RollingStone: 500 Albums", "Genre");
var albumArt = getColumn("RollingStone: 500 Albums", "Album Art");
var yearList = getColumn("RollingStone: 500 Albums", "Year");
//filtered list
var filteredAlbum = [];
var filteredArtist = [];
var filteredGenre = [];
var filteredArt = [];
var filteredYear = [];
generate();
onEvent("button1", "click", function( ) {
  updateScreen();
});
onEvent("button2", "click", function( ) {
  setScreen("screen2");
});
onEvent("button3", "click", function( ) {
  setScreen("screen1");
});
function generate() {
  for (var i = 0; i < albumList.length; i++) {
    if (albumList[i] == 1) {
      appendItem(filteredAlbum, albumList[i]);
      appendItem(filteredArtist, artistList[i]);
      appendItem(filteredArt, albumArt[i]);
      appendItem(filteredGenre, genreList[i]);
      appendItem(filteredYear, yearList[i]);
    }
  }
}
function updateScreen() {
  var index = randomNumber(0, albumList.length - 1);
  setText("albumTitle", albumList[index]);
  setText("artistTitle", artistList[index]);
  setText("year", yearList[index]);
  setText("genre", genreList[index]);
  setProperty("albumArt", "image", albumArt[index]);
}
onEvent("artistTitle", "change", function( ) {
	console.log("artistTitle entered text: " + getText("artistTitle"));
});
